public class PoliceReportFrame extends BaseFrame{ public PoliceReportFrame(){super("警察局通報走失",460,720);JPanel p=root();p.add(header("警局通報走失"));String[] vals={"王小美","新北市新店區北新路三段 205 號","2026/07/02 10:30","新店分局","02-2911-1170"};String[] labs={"走失者姓名","最後位置","最後時間","建議通報警局","警局電話"};JTextField[] fs=new JTextField[vals.length];for(int i=0;i<vals.length;i++){JLabel l=JapandiTheme.label(labs[i],0,13);l.setBounds(48,105+i*74,140,22);p.add(l);fs[i]=new JTextField(vals[i]);fs[i].setBounds(48,130+i*74,360,42);p.add(fs[i]);}JButton submit=JapandiTheme.primary("建立走失通報紀錄");submit.setBounds(48,535,360,50);submit.addActionListener(e->{new EmergencyServiceImpl().addLost(new LostReport(0,fs[0].getText(),fs[1].getText(),fs[2].getText(),fs[3].getText(),fs[4].getText(),"待處理"));JOptionPane.showMessageDialog(this,"已建立走失通報紀錄\n警局電話："+fs[4].getText()+"\n\n本系統僅記錄通報資訊，不會自動撥號。");});p.add(submit);p.add(bottomNav());} }